#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(Int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
template<typename T> inline void CV(vector<T> &v){vector<T> t;v.swap(t);}
const int INF=0x3f3f3f3f,N=510,M=1e5+10,NQ=1e7+10;int x[NQ],pp,kk,aa,bb,cc;
struct Ed{int u,v,w,x;}a[M];vector<int> MST,tmp;int n,m,cl[M],cr[M];
int fa[N];inline int fnd(int x){return fa[x]==x?x:fa[x]=fnd(fa[x]);}
struct Tup
{
	int x,y,z;inline bool operator < (const Tup&Q) const
		{return Q.x==x?(Q.y==y?z<Q.z:y<Q.y):x<Q.x;}
};vector<Tup> s;
int main()
{
	n=read();m=read();
	rep(1,m,i)a[i].u=read(),a[i].v=read(),a[i].w=read(),a[i].x=i;
	sort(a+1,a+m+1,[&](const Ed &x,const Ed &y){return x.w<y.w;});
	rep(1,m,i)
	{
		rep(1,n,u)fa[u]=u;fa[fnd(a[i].u)]=fnd(a[i].v);
		CV(tmp);tmp.push_back(i);int idx=0;
		for(int j:MST)
		{
			int x=fnd(a[j].u),y=fnd(a[j].v);
			if(x==y)idx=j;else fa[x]=y,tmp.push_back(j);
		}
		if(!idx)cl[a[i].x]=0; else cl[a[i].x]=(a[i].w+a[idx].w)/2+1;
		MST.swap(tmp);
		
	}
	sort(a+1,a+m+1,[&](const Ed &x,const Ed&y){return x.w>y.w;});
	CV(MST);rep(1,m,i)
	{
		rep(1,n,u)fa[u]=u;fa[fnd(a[i].u)]=fnd(a[i].v);
		CV(tmp);tmp.push_back(i);int idx=0;
		for(int j:MST)
		{
			int x=fnd(a[j].u),y=fnd(a[j].v);
			if(x==y)idx=j;else fa[x]=y,tmp.push_back(j);
		}
		if(!idx)cr[a[i].x]=INF;
		else 
		{
			if(a[i].w==a[idx].w)cr[a[i].x]=a[i].w-1;
			else cr[a[i].x]=(a[i].w+a[idx].w)/2;
		}
		MST.swap(tmp);
	}
	sort(a+1,a+m+1,[&](const Ed&x,const Ed&y){return x.x<y.x;});
	rep(1,m,i)if(cl[i]<=cr[i])
	{
		s.push_back({cl[i],-1,a[i].w});
		s.push_back({a[i].w,2,-2*a[i].w});
		s.push_back({cr[i]+1,-1,a[i].w});
	}
	sort(s.begin(),s.end());
	pp=read();kk=read();aa=read();bb=read();cc=read();
	rep(1,pp,i)x[i]=read();rep(pp+1,kk,i)x[i]=(1ll*x[i-1]*aa+bb)%cc;
	sort(x+1,x+kk+1);unsigned p=0;long long k=0,b=0,ans=0;;
	rep(1,kk,i)
	{
		while(p<s.size()&&s[p].x<=x[i])k+=s[p].y,b+=s[p++].z;
		ans^=(k*x[i]+b);
	}
	printf("%lld\n",ans);return 0;
}
